INSERT OR IGNORE INTO ic_seo_posts (category, slug, title, excerpt, content, tags, faq_json, status, author) VALUES ('surgery-code', 'endoscopic-surgery-benefit', '내시경 수술 보험금 — 수술로 인정될까', '내시경·복강경 시술이 약관상 수술에 해당하는지 판단하는 기준과, 수술보험금 청구 시 챙길 서류를 정리했습니다.', '<p>내시경·복강경 치료가 늘면서 "이것도 수술보험금이 되나"라는 질문이 많아졌습니다. 핵심은 약관이 정한 수술의 정의를 충족하는지입니다.</p>
<h2>약관상 수술의 정의</h2>
<p>대부분의 약관은 수술을 기구를 사용한 절단·절제 등 일정한 의료 행위로 정의합니다. 단순 검사나 처치는 제외되므로, 내시경이라도 절제 등 치료적 행위가 있었는지가 관건입니다.</p>
<h2>인정 가능성이 갈리는 예</h2>
<table>
<thead><tr><th>행위</th><th>경향</th></tr></thead>
<tbody>
<tr><td>내시경 용종 절제</td><td>수술로 인정되는 경우 많음</td></tr>
<tr><td>단순 내시경 검사</td><td>수술 정의 미충족 가능</td></tr>
</tbody>
</table>
<h2>청구 팁</h2>
<ul>
<li>시술명과 방법(절제 등)이 적힌 수술확인서 확보</li>
<li>조직검사·시술 기록으로 치료적 행위 입증</li>
</ul>
<p>같은 내시경이라도 무엇을 했는지에 따라 결과가 다르므로, 처치 내용이 구체적으로 기재된 서류가 중요합니다.</p>
<div class="post-key"><strong>핵심 포인트</strong><ul><li>약관상 수술 정의 충족이 관건</li><li>절제 등 치료 행위면 인정 가능성↑</li><li>방법이 적힌 수술확인서 확보</li></ul></div>
<p class="post-note">본 글은 일반적인 정보 제공을 위한 것으로, 구체적인 보장 여부는 가입하신 상품의 약관과 보험사 안내를 기준으로 합니다. 자세한 내용은 <a href="/disclaimer.html">면책조항</a>을 참고하세요.</p>', '["수술코드","내시경","수술보험금"]', '[{"q":"대장 용종 제거도 수술보험금이 되나요?","a":"내시경으로 용종을 절제했다면 수술로 인정되는 경우가 많습니다. 시술 방법이 기재된 서류로 확인하세요."},{"q":"단순 내시경 검사는요?","a":"치료 행위 없이 검사만 했다면 약관상 수술 정의를 충족하지 못해 제외될 수 있습니다."},{"q":"어떤 서류가 필요하나요?","a":"시술명·방법이 적힌 수술확인서나 진단서, 시술 기록이 도움이 됩니다."}]', 'published', 'InsureConnect 편집팀');
INSERT OR IGNORE INTO ic_seo_posts (category, slug, title, excerpt, content, tags, faq_json, status, author) VALUES ('surgery-code', 'cataract-surgery-claim', '백내장 수술 보험금 — 다초점렌즈 논란 정리', '백내장 수술의 입원·통원 분류와 다초점렌즈(비급여) 보장을 둘러싼 쟁점을 정리해 청구 전 이해를 돕습니다.', '<p>백내장 수술은 흔한 수술이지만 보험금 청구에서 쟁점이 많은 항목입니다. 특히 다초점렌즈 비용과 입원·통원 분류가 자주 문제 됩니다.</p>
<h2>수술 자체와 렌즈 비용</h2>
<ul>
<li>백내장 수술(혼탁 수정체 제거·인공수정체 삽입)은 치료 목적의 수술</li>
<li>다초점렌즈 등 비급여 렌즈 비용은 보장 범위·세대에 따라 다툼</li>
</ul>
<h2>입원·통원 분류</h2>
<p>백내장 수술이 통원으로 분류되는지 입원으로 보는지에 따라 실손 한도가 달라질 수 있습니다. 실제 입원 요건 충족 여부가 핵심입니다.</p>
<table>
<thead><tr><th>쟁점</th><th>판단 포인트</th></tr></thead>
<tbody>
<tr><td>렌즈 비용</td><td>치료 목적·약관 비급여 보장 범위</td></tr>
<tr><td>입원 여부</td><td>입원 요건 충족 여부</td></tr>
</tbody>
</table>
<h2>청구 전 확인</h2>
<p>가입한 실손 세대와 비급여 특약 조건, 진단서상 진단명·수술 방법을 확인하세요. 다초점렌즈 비용은 보장이 제한될 수 있으므로 사전에 보험사에 확인하는 것이 안전합니다.</p>
<div class="post-key"><strong>핵심 포인트</strong><ul><li>수술 자체와 렌즈 비용은 별개 쟁점</li><li>입원·통원 분류로 한도 변동</li><li>세대·비급여 특약 사전 확인</li></ul></div>
<p class="post-note">본 글은 일반적인 정보 제공을 위한 것으로, 구체적인 보장 여부는 가입하신 상품의 약관과 보험사 안내를 기준으로 합니다. 자세한 내용은 <a href="/disclaimer.html">면책조항</a>을 참고하세요.</p>', '["수술코드","백내장","다초점렌즈"]', '[{"q":"다초점렌즈 비용도 실손으로 받나요?","a":"세대·약관과 비급여 보장 범위에 따라 제한될 수 있습니다. 청구 전 보험사에 확인하는 것이 안전합니다."},{"q":"백내장 수술은 입원인가요?","a":"실제 입원 요건 충족 여부로 판단합니다. 분류에 따라 실손 한도가 달라질 수 있습니다."},{"q":"수술보험금은 받을 수 있나요?","a":"백내장 수술은 치료 목적의 수술로 인정되는 경우가 많습니다. 진단서·수술확인서로 확인하세요."}]', 'published', 'InsureConnect 편집팀');
INSERT OR IGNORE INTO ic_seo_posts (category, slug, title, excerpt, content, tags, faq_json, status, author) VALUES ('recruit-tips', 'career-fp-transition', '경력 설계사 이직 — 옮기기 전 점검할 것들', '경력 보험설계사가 소속을 옮길 때 고려할 고객 관리, 수수료 환수, 상품 취급 범위 등 현실적 체크포인트를 정리했습니다.', '<p>경력 설계사의 이직은 단순히 소속만 바꾸는 일이 아닙니다. 고객 관리와 수수료, 취급 상품 범위까지 영향을 미치므로 미리 점검이 필요합니다.</p>
<h2>이직 전 점검</h2>
<ul>
<li>기존 계약의 수수료 환수(클로백) 조건</li>
<li>관리 중인 고객의 이관·연속성</li>
<li>새 소속에서 취급 가능한 상품군(전속 vs GA)</li>
</ul>
<h2>전속과 GA의 차이</h2>
<table>
<thead><tr><th>구분</th><th>전속</th><th>GA(법인대리점)</th></tr></thead>
<tbody>
<tr><td>상품</td><td>소속 보험사 위주</td><td>여러 보험사 비교 판매</td></tr>
<tr><td>지원</td><td>본사 교육·시스템</td><td>대리점별 상이</td></tr>
</tbody>
</table>
<h2>현실적 조언</h2>
<p>이직 직후에는 정착지원이 끝나면 소득 변동이 클 수 있습니다. 고객 기반과 활동 루틴을 유지할 수 있는지, 환수 리스크는 없는지 따져보고 결정하는 것이 안전합니다.</p>
<div class="post-key"><strong>핵심 포인트</strong><ul><li>수수료 환수 조건 먼저 확인</li><li>전속·GA의 상품 범위 차이 이해</li><li>고객 기반·활동 루틴 유지 가능성 점검</li></ul></div>
<p class="post-note">본 글은 일반적인 정보 제공을 위한 것으로, 구체적인 보장 여부는 가입하신 상품의 약관과 보험사 안내를 기준으로 합니다. 자세한 내용은 <a href="/disclaimer.html">면책조항</a>을 참고하세요.</p>', '["리쿠르팅","경력이직","설계사"]', '[{"q":"이직하면 기존 수수료는 어떻게 되나요?","a":"계약 유지 조건에 따라 환수(클로백)가 발생할 수 있습니다. 이직 전 환수 규정을 반드시 확인하세요."},{"q":"전속과 GA 중 무엇이 유리한가요?","a":"여러 보험사를 비교 판매하려면 GA가, 본사 지원·교육을 중시하면 전속이 맞을 수 있습니다. 영업 스타일에 달렸습니다."},{"q":"고객을 데려갈 수 있나요?","a":"고객 관계는 이어갈 수 있어도 계약 이관은 제약이 있습니다. 연속성 측면을 점검하세요."}]', 'published', 'InsureConnect 편집팀');
INSERT OR IGNORE INTO ic_seo_posts (category, slug, title, excerpt, content, tags, faq_json, status, author) VALUES ('recruit-tips', 'fp-income-structure', '보험설계사 소득 구조 — 수수료는 어떻게 들어올까', '초년도·차년도 수수료, 유지수수료, 시책 등 보험설계사 소득의 구성과 환수 리스크를 이해하기 쉽게 정리했습니다.', '<p>보험설계사의 소득은 월급이 아니라 수수료 중심입니다. 구조를 이해하면 활동 계획과 소득 변동에 대비할 수 있습니다.</p>
<h2>수수료의 구성</h2>
<ul>
<li>초년도 수수료: 계약 첫해에 집중 지급</li>
<li>차년도(유지)수수료: 계약이 유지될 때 이어지는 보상</li>
<li>시책·수당: 회사 정책에 따른 추가 보상</li>
</ul>
<h2>유지율과 환수</h2>
<p>계약이 일찍 해지되면 이미 받은 수수료의 일부를 돌려줘야 하는 환수가 발생할 수 있습니다. 그래서 무리한 판매보다 유지가 잘 되는 건강한 계약이 장기 소득에 유리합니다.</p>
<table>
<thead><tr><th>요소</th><th>특징</th></tr></thead>
<tbody>
<tr><td>초년도</td><td>소득 집중, 변동 큼</td></tr>
<tr><td>유지수수료</td><td>안정적 기반</td></tr>
<tr><td>환수</td><td>조기 해지 시 부담</td></tr>
</tbody>
</table>
<p>초기에는 소득이 들쭉날쭉할 수 있으므로, 유지수수료 기반을 쌓아 안정적인 구조를 만드는 것이 목표가 됩니다.</p>
<div class="post-key"><strong>핵심 포인트</strong><ul><li>초년도 집중 + 유지수수료 기반</li><li>조기 해지는 환수 리스크</li><li>건강한 유지가 장기 소득의 핵심</li></ul></div>
<p class="post-note">본 글은 일반적인 정보 제공을 위한 것으로, 구체적인 보장 여부는 가입하신 상품의 약관과 보험사 안내를 기준으로 합니다. 자세한 내용은 <a href="/disclaimer.html">면책조항</a>을 참고하세요.</p>', '["리쿠르팅","수수료","소득구조"]', '[{"q":"수수료는 매달 일정한가요?","a":"아닙니다. 초년도 수수료가 집중되고 이후 유지수수료가 이어져 월별 변동이 큽니다."},{"q":"환수는 왜 생기나요?","a":"계약이 조기 해지되면 이미 지급된 수수료의 일부를 환수합니다. 유지가 잘 되는 계약이 중요합니다."},{"q":"안정적 소득을 만들려면?","a":"유지율 높은 계약을 꾸준히 쌓아 유지수수료 기반을 키우는 것이 핵심입니다."}]', 'published', 'InsureConnect 편집팀');
INSERT OR IGNORE INTO ic_seo_posts (category, slug, title, excerpt, content, tags, faq_json, status, author) VALUES ('underwrite', 'occupation-risk-class', '직업급수와 상해보험 — 위험한 직업은 가입이 어려울까', '상해보험 인수에서 직업급수가 보험료·가입에 미치는 영향과, 직업 변경 시 알릴 의무를 정리했습니다.', '<p>상해보험은 다치는 위험을 보장하므로, 직업의 위험도가 인수와 보험료에 큰 영향을 줍니다. 이를 직업급수(상해급수)로 구분합니다.</p>
<h2>직업급수란</h2>
<p>사무직처럼 위험이 낮은 직업과 생산·건설·고소 작업처럼 위험이 높은 직업을 등급으로 나눈 것입니다. 위험이 높을수록 보험료가 오르거나 일부 보장이 제한될 수 있습니다.</p>
<table>
<thead><tr><th>구분</th><th>예시</th><th>경향</th></tr></thead>
<tbody>
<tr><td>저위험</td><td>사무직</td><td>표준 인수</td></tr>
<tr><td>고위험</td><td>생산·건설·운송</td><td>할증·제한 가능</td></tr>
</tbody>
</table>
<h2>직업이 바뀌면</h2>
<ul>
<li>위험이 큰 직업으로 변경되면 보험사에 알려야 함(통지의무)</li>
<li>알리지 않으면 보험금 지급에 불이익이 생길 수 있음</li>
</ul>
<p>가입 후 이직·전직으로 위험도가 달라지면 반드시 보험사에 통지해, 보장에 공백이 생기지 않도록 해야 합니다.</p>
<div class="post-key"><strong>핵심 포인트</strong><ul><li>직업 위험도가 인수·보험료 좌우</li><li>고위험 직업은 할증·제한 가능</li><li>직업 변경 시 통지의무 이행</li></ul></div>
<p class="post-note">본 글은 일반적인 정보 제공을 위한 것으로, 구체적인 보장 여부는 가입하신 상품의 약관과 보험사 안내를 기준으로 합니다. 자세한 내용은 <a href="/disclaimer.html">면책조항</a>을 참고하세요.</p>', '["인수사례","직업급수","상해보험"]', '[{"q":"위험한 직업이면 상해보험을 못 드나요?","a":"거절만 있는 것은 아닙니다. 보험료 할증이나 일부 보장 제한으로 인수되는 경우가 많습니다."},{"q":"직업이 바뀌면 꼭 알려야 하나요?","a":"특히 위험도가 높아지는 변경은 통지의무 대상입니다. 알리지 않으면 보험금에 불이익이 생길 수 있습니다."},{"q":"사무직이면 보험료가 싼가요?","a":"상해 위험이 낮아 상대적으로 유리한 편입니다. 다만 보장·상품에 따라 다릅니다."}]', 'published', 'InsureConnect 편집팀');
INSERT OR IGNORE INTO ic_seo_posts (category, slug, title, excerpt, content, tags, faq_json, status, author) VALUES ('disease-code', 'injury-classification-codes', '상해(손상) 분류 코드 — 사고로 다쳤을 때의 보장 기준', '상해보험에서 손상(S·T 코드) 분류가 보장 판단에 어떻게 쓰이는지와, 질병과의 구분 쟁점을 정리했습니다.', '<p>질병코드는 질병뿐 아니라 사고로 인한 손상(상해)도 분류합니다. 상해보험에서는 이 손상 분류가 보장 판단의 근거가 됩니다.</p>
<h2>상해와 질병의 구분</h2>
<p>상해보험은 ''급격하고 우연한 외래의 사고''로 인한 손해를 보장합니다. 손상 코드(외상 등)는 사고성 손해임을 뒷받침하는 자료가 됩니다. 반면 내부적 원인(질병)에 의한 것은 상해보험 대상이 아닐 수 있습니다.</p>
<table>
<thead><tr><th>구분</th><th>성격</th></tr></thead>
<tbody>
<tr><td>상해(손상)</td><td>외래의 사고성 손해</td></tr>
<tr><td>질병</td><td>신체 내부 원인</td></tr>
</tbody>
</table>
<h2>왜 구분이 중요한가</h2>
<ul>
<li>상해보험과 질병보험은 보장 대상이 다름</li>
<li>같은 결과라도 원인이 사고냐 질병이냐에 따라 지급이 달라짐</li>
</ul>
<p>진단서의 코드와 사고 경위가 일치하도록 정리하면 보장 판단이 명확해집니다. 원인 다툼이 있으면 의무기록과 사고 정황이 핵심 자료가 됩니다.</p>
<div class="post-key"><strong>핵심 포인트</strong><ul><li>상해=외래의 사고성 손해</li><li>원인(사고/질병)이 보장 대상 결정</li><li>코드와 사고 경위 일치가 중요</li></ul></div>
<p class="post-note">본 글은 일반적인 정보 제공을 위한 것으로, 구체적인 보장 여부는 가입하신 상품의 약관과 보험사 안내를 기준으로 합니다. 자세한 내용은 <a href="/disclaimer.html">면책조항</a>을 참고하세요.</p>', '["질병코드","상해","손상분류"]', '[{"q":"넘어져 다쳤는데 상해보험이 안 된다고요?","a":"기존 질병이 원인으로 작용했다고 보면 상해성에 다툼이 생길 수 있습니다. 사고 경위와 의무기록이 중요합니다."},{"q":"상해와 질병은 어떻게 구분하나요?","a":"급격·우연·외래의 사고면 상해, 신체 내부 원인이면 질병으로 봅니다. 코드와 경위로 판단합니다."},{"q":"코드가 보장에 영향을 주나요?","a":"네. 손상 코드는 사고성 손해를 뒷받침하는 근거가 되어 보장 판단에 활용됩니다."}]', 'published', 'InsureConnect 편집팀');
INSERT OR IGNORE INTO ic_seo_posts (category, slug, title, excerpt, content, tags, faq_json, status, author) VALUES ('cancer', 'cancer-hospitalization-benefit', '암 입원·요양병원 보장 — 어디까지 인정될까', '암 치료를 위한 입원과 요양병원 입원의 보장 인정 기준, 치료 목적성 쟁점을 정리했습니다.', '<p>암 치료 과정에서 입원, 특히 요양병원 입원이 길어지면 보장 여부를 두고 다툼이 생길 수 있습니다. 핵심은 ''암의 치료를 직접 목적으로 한 입원''인지입니다.</p>
<h2>치료 목적성</h2>
<ul>
<li>수술·항암·방사선 등 적극적 치료를 위한 입원은 인정 경향</li>
<li>단순 요양·회복 목적의 장기 입원은 보장이 제한될 수 있음</li>
</ul>
<h2>요양병원 쟁점</h2>
<p>요양병원 입원은 치료와 요양의 경계가 모호해, 입원의 필요성과 치료 내용이 쟁점이 됩니다. 적극적 항암치료와 병행되는 입원인지가 판단에 중요합니다.</p>
<table>
<thead><tr><th>입원 성격</th><th>경향</th></tr></thead>
<tbody>
<tr><td>적극적 치료 병행</td><td>인정 가능성↑</td></tr>
<tr><td>단순 요양</td><td>제한 가능</td></tr>
</tbody>
</table>
<h2>청구 팁</h2>
<p>입원의 의학적 필요성과 치료 내용이 드러나는 진료기록·소견서를 확보하세요. 다툼이 크면 분쟁조정으로 다툴 수 있습니다.</p>
<div class="post-key"><strong>핵심 포인트</strong><ul><li>암 치료 직접 목적 입원이 핵심</li><li>요양병원은 필요성·치료내용이 쟁점</li><li>진료기록·소견서로 입증</li></ul></div>
<p class="post-note">본 글은 일반적인 정보 제공을 위한 것으로, 구체적인 보장 여부는 가입하신 상품의 약관과 보험사 안내를 기준으로 합니다. 자세한 내용은 <a href="/disclaimer.html">면책조항</a>을 참고하세요.</p>', '["암보험","암입원","요양병원"]', '[{"q":"요양병원 입원도 암 입원으로 보장되나요?","a":"적극적 암 치료와 병행되는 입원이면 인정 가능성이 높지만, 단순 요양 목적이면 제한될 수 있습니다."},{"q":"무엇으로 치료 목적을 입증하나요?","a":"입원의 필요성과 치료 내용이 담긴 진료기록·소견서가 핵심 자료입니다."},{"q":"다툼이 생기면 어떻게 하나요?","a":"의학적 자료를 보강하고, 이견이 크면 금융분쟁조정을 활용할 수 있습니다."}]', 'published', 'InsureConnect 편집팀');
INSERT OR IGNORE INTO ic_seo_posts (category, slug, title, excerpt, content, tags, faq_json, status, author) VALUES ('actual-loss', 'silbi-renewal-premium-rise', '실손보험료가 오르는 이유 — 갱신과 인상 구조', '실손보험료가 갱신마다 오르는 원리(손해율·연령·재가입)와 부담을 줄이는 방법을 정리했습니다.', '<p>실손보험은 갱신할 때마다 보험료가 오르는 경우가 많아 부담을 느끼는 분이 많습니다. 인상에는 몇 가지 구조적 이유가 있습니다.</p>
<h2>오르는 이유</h2>
<ul>
<li>손해율: 전체 가입자의 의료 이용이 늘면 보험료에 반영</li>
<li>연령 증가: 나이가 들수록 위험률 상승</li>
<li>재가입 주기: 일정 주기마다 갱신·재가입하며 조정</li>
</ul>
<h2>세대별 차이</h2>
<p>오래된 실손은 보장이 넓은 대신 인상폭이 큰 경향이 있고, 4세대는 비급여 이용량에 따라 할인·할증이 적용됩니다. 병원 이용이 적다면 4세대가 부담 면에서 유리할 수 있습니다.</p>
<table>
<thead><tr><th>요인</th><th>영향</th></tr></thead>
<tbody>
<tr><td>손해율</td><td>전체 인상 압력</td></tr>
<tr><td>연령</td><td>개인 위험률↑</td></tr>
</tbody>
</table>
<h2>부담 줄이기</h2>
<p>병원 이용 패턴을 고려해 세대 전환을 검토하거나, 중복가입을 정리해 불필요한 보험료를 줄일 수 있습니다. 다만 전환은 보장 축소를 동반할 수 있어 신중히 판단해야 합니다.</p>
<div class="post-key"><strong>핵심 포인트</strong><ul><li>손해율·연령·재가입이 인상 요인</li><li>이용 적으면 4세대가 유리할 수 있음</li><li>중복 정리·전환은 신중히</li></ul></div>
<p class="post-note">본 글은 일반적인 정보 제공을 위한 것으로, 구체적인 보장 여부는 가입하신 상품의 약관과 보험사 안내를 기준으로 합니다. 자세한 내용은 <a href="/disclaimer.html">면책조항</a>을 참고하세요.</p>', '["실손보험","보험료인상","갱신"]', '[{"q":"실손보험료는 왜 매년 오르나요?","a":"전체 손해율과 개인의 연령 증가, 재가입 주기에 따른 조정이 보험료에 반영되기 때문입니다."},{"q":"4세대로 바꾸면 보험료가 줄나요?","a":"병원 이용이 적다면 줄어들 수 있습니다. 다만 자기부담이 늘 수 있어 이용 패턴을 고려해야 합니다."},{"q":"보험료 부담을 줄이는 방법은?","a":"중복가입 정리, 이용 패턴에 맞는 세대 전환 검토 등이 있습니다. 보장 축소를 동반하니 신중히 결정하세요."}]', 'published', 'InsureConnect 편집팀');
INSERT OR IGNORE INTO ic_seo_posts (category, slug, title, excerpt, content, tags, faq_json, status, author) VALUES ('claim', 'accident-vs-disease-classification', '상해와 질병 구분 — 같은 입원도 보험금이 다른 이유', '상해보험금과 질병보험금의 차이, 원인 구분이 지급에 미치는 영향과 분쟁 시 입증 포인트를 정리했습니다.', '<p>보험금 청구에서 같은 치료라도 원인이 상해냐 질병이냐에 따라 보장과 금액이 달라질 수 있습니다. 보장 담보가 서로 다르기 때문입니다.</p>
<h2>상해와 질병</h2>
<ul>
<li>상해: 급격하고 우연한 외래의 사고로 인한 손해</li>
<li>질병: 신체 내부 원인에 의한 손해</li>
</ul>
<h2>왜 구분이 중요한가</h2>
<p>상해 담보와 질병 담보는 가입 여부·한도가 다를 수 있습니다. 예컨대 상해 입원일당만 있고 질병 입원일당이 없다면, 질병으로 인한 입원은 해당 보장을 받지 못합니다.</p>
<table>
<thead><tr><th>원인</th><th>해당 담보</th></tr></thead>
<tbody>
<tr><td>사고(상해)</td><td>상해 입원·수술·후유장해</td></tr>
<tr><td>질병</td><td>질병 입원·수술·진단비</td></tr>
</tbody>
</table>
<h2>분쟁 시 입증</h2>
<p>원인이 모호하면 사고 경위, 최초 진료기록, 진단서의 코드가 핵심 근거가 됩니다. 사고 직후의 의무기록이 상해성 입증에 특히 중요합니다.</p>
<div class="post-key"><strong>핵심 포인트</strong><ul><li>상해·질병은 담보가 다름</li><li>가입 담보에 따라 지급 여부 결정</li><li>사고 경위·초진 기록이 입증 핵심</li></ul></div>
<p class="post-note">본 글은 일반적인 정보 제공을 위한 것으로, 구체적인 보장 여부는 가입하신 상품의 약관과 보험사 안내를 기준으로 합니다. 자세한 내용은 <a href="/disclaimer.html">면책조항</a>을 참고하세요.</p>', '["보험금청구","상해","질병"]', '[{"q":"상해랑 질병이 보험금이 다른가요?","a":"해당 담보가 다릅니다. 가입한 보장(상해/질병)에 따라 지급 여부와 한도가 달라질 수 있습니다."},{"q":"원인이 애매하면 어떻게 하나요?","a":"사고 경위와 최초 진료기록, 진단서 코드가 판단 근거가 됩니다. 초진 기록을 잘 남기는 것이 중요합니다."},{"q":"둘 다 보장받을 수 있나요?","a":"하나의 사건은 보통 한 가지 원인으로 판단됩니다. 다만 보장별로 별개 청구가 가능한 경우가 있습니다."}]', 'published', 'InsureConnect 편집팀');
INSERT OR IGNORE INTO ic_seo_posts (category, slug, title, excerpt, content, tags, faq_json, status, author) VALUES ('car', 'car-insurance-renewal-tips', '자동차보험 갱신 점검 — 매년 확인하면 좋은 것들', '자동차보험 갱신 시 보장 범위·특약·할인을 점검해 보험료를 최적화하는 체크포인트를 정리했습니다.', '<p>자동차보험은 1년 단위로 갱신됩니다. 갱신 시점에 보장과 할인을 점검하면 불필요한 보험료를 줄이고 보장 공백을 막을 수 있습니다.</p>
<h2>갱신 시 점검 목록</h2>
<ul>
<li>대인 II·대물 한도(무한/충분한 한도인지)</li>
<li>자차 가입 여부와 자기부담금 설정</li>
<li>운전자 범위(가족·부부 한정 등)와 연령 한정</li>
<li>마일리지·블랙박스·안전운전 할인 적용</li>
</ul>
<h2>운전 환경 변화 반영</h2>
<table>
<thead><tr><th>변화</th><th>점검</th></tr></thead>
<tbody>
<tr><td>주행거리 감소</td><td>마일리지 특약</td></tr>
<tr><td>운전자 변경</td><td>운전자 범위·연령 한정</td></tr>
<tr><td>차량 노후</td><td>자차 실익 재검토</td></tr>
</tbody>
</table>
<h2>비교 견적</h2>
<p>갱신 전 여러 보험사 견적을 비교하면 같은 보장도 보험료 차이가 날 수 있습니다. 다만 한도를 무리하게 낮춰 보장 공백이 생기지 않도록 주의하세요.</p>
<div class="post-key"><strong>핵심 포인트</strong><ul><li>한도·자차·운전자 범위 점검</li><li>운전 환경 변화 반영</li><li>비교 견적, 단 보장 공백 주의</li></ul></div>
<p class="post-note">본 글은 일반적인 정보 제공을 위한 것으로, 구체적인 보장 여부는 가입하신 상품의 약관과 보험사 안내를 기준으로 합니다. 자세한 내용은 <a href="/disclaimer.html">면책조항</a>을 참고하세요.</p>', '["자동차보험","갱신","보험료절약"]', '[{"q":"갱신 때 보험료를 줄이려면?","a":"운전자 범위·연령 한정, 마일리지 특약, 차량 노후 시 자차 재검토 등으로 조정할 수 있습니다. 비교 견적도 도움이 됩니다."},{"q":"한도를 낮추면 보험료가 주나요?","a":"줄지만 보장 공백 위험이 커집니다. 특히 대인·대물 한도는 충분히 유지하는 것이 안전합니다."},{"q":"운전자 범위는 무엇인가요?","a":"보장되는 운전자의 범위(본인·부부·가족 등)와 연령 한정입니다. 좁힐수록 보험료가 낮아집니다."}]', 'published', 'InsureConnect 편집팀');
INSERT OR IGNORE INTO ic_seo_posts (category, slug, title, excerpt, content, tags, faq_json, status, author) VALUES ('practice', 'needs-based-selling', '니즈 기반 영업 — 상품을 팔기 전에 필요를 찾는 법', '고객의 실제 필요에서 출발하는 니즈 기반 영업의 흐름과 질문 기술, 컴플라이언스 관점을 정리했습니다.', '<p>좋은 보험 영업은 상품을 먼저 내미는 것이 아니라 고객의 필요를 함께 찾는 데서 시작합니다. 이것이 니즈 기반 영업입니다.</p>
<h2>니즈를 찾는 질문</h2>
<ul>
<li>현재 가족·소득·지출 상황</li>
<li>가장 걱정되는 위험(질병·사고·노후)</li>
<li>기존 보장에서 부족하다고 느끼는 점</li>
</ul>
<h2>흐름</h2>
<table>
<thead><tr><th>단계</th><th>핵심</th></tr></thead>
<tbody>
<tr><td>경청</td><td>고객이 말하게 하기</td></tr>
<tr><td>니즈 정리</td><td>위험·우선순위 합의</td></tr>
<tr><td>맞춤 제안</td><td>필요에 맞는 보장 설계</td></tr>
</tbody>
</table>
<h2>컴플라이언스</h2>
<p>니즈에 맞지 않는 과도한 보장이나 부적합한 상품 권유는 적합성 원칙에 어긋납니다. 고객의 예산과 필요에 맞춘 제안이 장기 신뢰와 유지율을 만듭니다.</p>
<div class="post-key"><strong>핵심 포인트</strong><ul><li>상품보다 필요를 먼저</li><li>경청 → 니즈 정리 → 맞춤 제안</li><li>적합성 원칙 준수가 신뢰의 기반</li></ul></div>
<p class="post-note">본 글은 일반적인 정보 제공을 위한 것으로, 구체적인 보장 여부는 가입하신 상품의 약관과 보험사 안내를 기준으로 합니다. 자세한 내용은 <a href="/disclaimer.html">면책조항</a>을 참고하세요.</p>', '["설계사실무","니즈영업","상담기술"]', '[{"q":"니즈 영업이 더 효과적인가요?","a":"고객의 실제 필요에 맞추면 계약 만족도와 유지율이 높아져 장기적으로 효과적입니다."},{"q":"어떤 질문부터 하나요?","a":"가족·소득 상황과 가장 걱정되는 위험, 기존 보장의 부족함을 묻는 것부터 시작합니다."},{"q":"과도한 보장 권유는 왜 문제인가요?","a":"적합성 원칙에 어긋나고 해지·민원으로 이어질 수 있어 예산과 필요에 맞춘 제안이 중요합니다."}]', 'published', 'InsureConnect 편집팀');
INSERT OR IGNORE INTO ic_seo_posts (category, slug, title, excerpt, content, tags, faq_json, status, author) VALUES ('terms', 'insurance-glossary-basics', '헷갈리는 보험 용어 정리 — 보험료·보험금·해지환급금', '보험료와 보험금, 피보험자와 수익자, 해지환급금 등 자주 헷갈리는 기본 용어를 한 번에 정리했습니다.', '<p>보험을 어렵게 느끼게 만드는 첫 번째 장벽은 용어입니다. 자주 헷갈리는 기본 용어만 정리해도 약관과 상담 내용이 훨씬 잘 이해됩니다.</p>
<h2>꼭 알아야 할 용어</h2>
<table>
<thead><tr><th>용어</th><th>뜻</th></tr></thead>
<tbody>
<tr><td>보험료</td><td>내가 내는 돈</td></tr>
<tr><td>보험금</td><td>사고·질병 시 받는 돈</td></tr>
<tr><td>계약자</td><td>계약 체결·보험료 납입 주체</td></tr>
<tr><td>피보험자</td><td>보장의 대상이 되는 사람</td></tr>
<tr><td>수익자</td><td>보험금을 받는 사람</td></tr>
<tr><td>해지환급금</td><td>중도 해지 시 돌려받는 금액</td></tr>
</tbody>
</table>
<h2>혼동 주의</h2>
<ul>
<li>보험료(납입) vs 보험금(수령) — 방향이 반대</li>
<li>계약자·피보험자·수익자는 서로 다를 수 있음</li>
</ul>
<p>특히 계약자, 피보험자, 수익자를 누구로 지정하느냐에 따라 보장과 세금, 보험금 수령자가 달라질 수 있어 가입 시 정확히 정하는 것이 중요합니다.</p>
<div class="post-key"><strong>핵심 포인트</strong><ul><li>보험료=납입, 보험금=수령</li><li>계약자·피보험자·수익자 구분</li><li>지정에 따라 보장·세금·수령자 달라짐</li></ul></div>
<p class="post-note">본 글은 일반적인 정보 제공을 위한 것으로, 구체적인 보장 여부는 가입하신 상품의 약관과 보험사 안내를 기준으로 합니다. 자세한 내용은 <a href="/disclaimer.html">면책조항</a>을 참고하세요.</p>', '["약관해설","보험용어","기초"]', '[{"q":"보험료와 보험금이 헷갈려요.","a":"보험료는 내가 내는 돈, 보험금은 사고·질병 시 받는 돈입니다. 방향이 반대입니다."},{"q":"피보험자와 수익자가 같아야 하나요?","a":"다를 수 있습니다. 피보험자는 보장 대상, 수익자는 보험금을 받는 사람으로 별도로 지정합니다."},{"q":"해지환급금은 낸 보험료만큼 돌려받나요?","a":"특히 초기에는 사업비 등으로 낸 보험료보다 적을 수 있습니다. 환급률은 시간이 지나며 회복됩니다."}]', 'published', 'InsureConnect 편집팀');
